SELECT bs_per_bldg.eiaid, ts_aggr.state, ts_aggr.timestamp AS timestamp, sum(bs_per_bldg.tract_count) AS sample_count, sum(bs_per_bldg.bldg_weight) AS units_count, sum(ts_aggr."bs__out.site_energy.total.energy_consumption" * bs_per_bldg.bldg_weight) AS "site_energy.total.energy_consumption" FROM (SELECT ts_flat.timestamp AS timestamp, ts_flat.bldg_id AS bldg_id, ts_flat.state AS state, sum(ts_flat."_v__out.site_energy.total.energy_consumption") AS "bs__out.site_energy.total.energy_consumption", count(*) AS _inner_rows FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, resstock_2024_amy2018_release_2_by_state_vu.state AS state, resstock_2024_amy2018_release_2_by_state_vu."out.site_energy.total.energy_consumption" AS "_v__out.site_energy.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (0) AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO') AS ts_flat GROUP BY ts_flat.timestamp, ts_flat.bldg_id, ts_flat.state) AS ts_aggr JOIN (SELECT bs.bldg_id AS bldg_id, arbitrary(eiaid_weights.eiaid) AS eiaid, sum(bs.weight * eiaid_weights.weight) AS bldg_weight, count(*) AS tract_count FROM resstock_2024_amy2018_release_2_metadata AS bs JOIN eiaid_weights ON bs."in.county" = eiaid_weights.gisjoin WHERE bs.upgrade = 0 AND bs."in.state" = 'CO' AND eiaid_weights.eiaid = '4110' GROUP BY bs.bldg_id) AS bs_per_bldg ON bs_per_bldg.bldg_id = ts_aggr.bldg_id GROUP BY 1, 2, 3 ORDER BY 1, 2, 3